const llm = $input.first().json;

let data = llm.output ?? llm.text ?? llm.response ?? llm;

if (typeof data === 'string') {
  data = data.replace(/```json/g, '').replace(/```/g, '').trim();
  data = JSON.parse(data);
}

const entrada = $('Renombrar Campos').first().json;

const intencion = data.intencion || 'desconocido';
const duracion = Number(data.duracion) || 30;

function crearIntervalo(fecha, hora, duracionMinutos) {
  if (!fecha || !hora) {
    return {
      start_datetime: null,
      end_datetime: null
    };
  }

  const start_datetime = `${fecha}T${hora}:00-05:00`;

  const end_datetime = new Date(
    new Date(start_datetime).getTime() + duracionMinutos * 60000
  ).toISOString();

  return {
    start_datetime,
    end_datetime
  };
}

// Para reservar normalmente
const reserva = crearIntervalo(data.fecha, data.hora, duracion);

// Para cambiar hora
const nueva_fecha =
  data.nueva_fecha || (intencion === 'cambiar_hora' ? data.fecha : null);

const nueva_hora =
  data.nueva_hora || (intencion === 'cambiar_hora' ? data.hora : null);

const cambio = crearIntervalo(nueva_fecha, nueva_hora, duracion);

const chat_id = entrada.chat_id;

return [
  {
    json: {
      ...entrada,

      intencion,
      servicio: data.servicio || null,

      fecha: data.fecha || null,
      hora: data.hora || null,
      duracion,
      respuesta_sugerida: data.respuesta_sugerida || null,

      start_datetime: reserva.start_datetime,
      end_datetime: reserva.end_datetime,

      nueva_fecha,
      nueva_hora,
      nueva_start_datetime: cambio.start_datetime,
      nueva_end_datetime: cambio.end_datetime,

      buscar_evento_por_chat: `Chat ID: ${chat_id}`,

      tiene_fecha_y_hora: reserva.start_datetime !== null,
      tiene_nuevo_horario: cambio.start_datetime !== null
    }
  }
];

const normalizado = $('Normalizar IA').first().json;

const eventos = $input.all()
  .map(item => item.json)
  .filter(evento => evento && evento.id);

function obtenerInicio(evento) {
  return (
    evento.start?.dateTime ||
    evento.start?.date ||
    evento.startTime ||
    evento.start ||
    null
  );
}

function obtenerFin(evento) {
  return (
    evento.end?.dateTime ||
    evento.end?.date ||
    evento.endTime ||
    evento.end ||
    null
  );
}

function obtenerDuracionDesdeDescripcion(descripcion) {
  if (!descripcion) return null;

  const match = descripcion.match(/Duraci[oó]n:\s*(\d+)\s*minutos?/i);

  if (!match) return null;

  return Number(match[1]);
}

const ahora = new Date();

const eventosValidos = eventos
  .filter(evento => {
    const descripcion = evento.description || '';
    const inicio = obtenerInicio(evento);

    const tieneChat = descripcion.includes(`Chat ID: ${normalizado.chat_id}`);
    const estaCancelada = descripcion.toLowerCase().includes('estado: cancelada');
    const esFutura = inicio ? new Date(inicio) >= ahora : true;

    return tieneChat && !estaCancelada && esFutura;
  })
  .sort((a, b) => {
    const inicioA = new Date(obtenerInicio(a) || 0);
    const inicioB = new Date(obtenerInicio(b) || 0);
    return inicioA - inicioB;
  });

if (eventosValidos.length === 0) {
  return [
    {
      json: {
        ...normalizado,
        evento_encontrado: false,
        event_id: null,
        evento_actual_summary: null,
        evento_actual_description: null,
        evento_actual_inicio: null,
        evento_actual_fin: null,
        duracion_original_minutos: null,
        debug_eventos_recibidos: eventos.length
      }
    }
  ];
}

const evento = eventosValidos[0];

const inicioOriginal = obtenerInicio(evento);
const finOriginal = obtenerFin(evento);
const descripcionOriginal = evento.description || '';

let duracionOriginalMinutos = obtenerDuracionDesdeDescripcion(descripcionOriginal);

if (!duracionOriginalMinutos && inicioOriginal && finOriginal) {
  duracionOriginalMinutos = Math.round(
    (new Date(finOriginal).getTime() - new Date(inicioOriginal).getTime()) / 60000
  );
}

if (!duracionOriginalMinutos) {
  duracionOriginalMinutos = 30;
}

return [
  {
    json: {
      ...normalizado,
      evento_encontrado: true,
      event_id: evento.id,
      evento_actual_summary: evento.summary || 'Cita BarberBot',
      evento_actual_description: descripcionOriginal,
      evento_actual_inicio: inicioOriginal,
      evento_actual_fin: finOriginal,
      duracion_original_minutos: duracionOriginalMinutos,
      debug_eventos_recibidos: eventos.length
    }
  }
];

