const base = $('Normalizar IA').first().json;
const chatId = String(base.chat_id || '').trim();

// Normaliza textos para evitar problemas con mayúsculas, tildes o espacios
function normalizarTexto(valor) {
  return String(valor || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

// Filas encontradas en Google Sheets para este cliente
const filas = $input.all()
  .map(item => item.json)
  .filter(row => String(row.chat_id || '').trim() === chatId);

// Contadores
let asistencias = 0;
let noShows = 0;
let canceladasTarde = 0;
let canceladasATiempo = 0;
let reprogramadas = 0;
let pendientes = 0;

for (const row of filas) {
  const resultado = normalizarTexto(
    row.resultado_cita ||
    row.estado_cita ||
    row.resultado_final ||
    ''
  );

  if (
    resultado === 'asistio'
  ) {
    asistencias++;
  }

  else if (
    resultado === 'no asistio'
  ) {
    noShows++;
  }

  else if (
    resultado === 'cancelada_tarde'
  ) {
    canceladasTarde++;
  }

  else if (
    resultado === 'cancelada a tiempo'
  ) {
    canceladasATiempo++;
  }

  else if (
    resultado === 'reprogramada'
  ) {
    reprogramadas++;
  }

  else {
    pendientes++;
  }
}

// Solo contamos eventos que realmente sirven para medir cumplimiento
const eventosEvaluables = asistencias + noShows + canceladasTarde;

// Valor neutral para clientes nuevos o sin historial suficiente
const valorNeutral = 0.6;

// Si no hay eventos evaluables, no fingimos que conocemos el historial
let cumplimientoObservado = null;

if (eventosEvaluables > 0) {
  cumplimientoObservado = asistencias / eventosEvaluables;
}

// Confianza en el historial:
// con pocas citas, no confiamos demasiado;
// con 5 o más citas evaluables, ya confiamos bastante.
const confianzaHistorial = Math.min(1, eventosEvaluables / 5);

let historial_cliente;

if (cumplimientoObservado === null) {
  historial_cliente = valorNeutral;
} else {
  historial_cliente =
    valorNeutral * (1 - confianzaHistorial) +
    cumplimientoObservado * confianzaHistorial;
}

// Limitar entre 0 y 1
historial_cliente = Math.max(0, Math.min(1, historial_cliente));
historial_cliente = Number(historial_cliente.toFixed(2));

return [
  {
    json: {
      ...base,

      historial_cliente,
      historial_confianza: Number(confianzaHistorial.toFixed(2)),
      historial_eventos_evaluables: eventosEvaluables,

      historial_asistencias: asistencias,
      historial_no_shows: noShows,
      historial_canceladas_tarde: canceladasTarde,
      historial_canceladas_a_tiempo: canceladasATiempo,
      historial_reprogramadas: reprogramadas,
      historial_pendientes: pendientes
    }
  }
];

// Este nodo debe ir DESPUÉS del nodo que calcula el historial del cliente.
// Por eso usamos $input.first().json, porque ya viene con historial_cliente.
const item = $input.first().json;

const fecha = item.fecha;
const hora = item.hora;
const servicio = item.servicio;
const duracion = Number(item.duracion) || 30;

// Normalizamos la hora por si viene como "15:00" o "15:00:00"
const horaLimpia = String(hora || '').slice(0, 5);

// Fecha y hora de la cita
const ahora = new Date();
const inicioCita = new Date(`${fecha}T${horaLimpia}:00-05:00`);

const diferenciaMs = inicioCita.getTime() - ahora.getTime();

const anticipacion_horas = Number.isFinite(diferenciaMs)
  ? Math.max(0, Math.round(diferenciaMs / 36e5))
  : 0;

const hora_cita = Number(horaLimpia.split(':')[0]) || 0;

// Historial real calculado desde Google Sheets.
// Si por alguna razón no viene, usamos un valor neutral.
let historial_cliente = Number(item.historial_cliente);

if (!Number.isFinite(historial_cliente)) {
  historial_cliente = 0.6;
}

// Lo limitamos entre 0 y 1
historial_cliente = Math.max(0, Math.min(1, historial_cliente));

// Confianza del historial, viene del nodo anterior.
// No es obligatoria para el cálculo, pero sirve para justificar y mostrar.
const historial_confianza = Number(item.historial_confianza || 0);

// Confirmación del cliente.
// No mide historial, sino qué tan completa está la solicitud actual.
const tieneServicio = Boolean(servicio);
const tieneFecha = Boolean(fecha);
const tieneHora = Boolean(hora);

let confirmacion_cliente = 0.3;

if (tieneServicio && tieneFecha && tieneHora) {
  confirmacion_cliente = 0.85;
} else if (tieneFecha && tieneHora) {
  confirmacion_cliente = 0.65;
} else if (tieneFecha || tieneHora || tieneServicio) {
  confirmacion_cliente = 0.45;
}

// Funciones de pertenencia difusa

function bajo(x, a, b) {
  if (x <= a) return 1;
  if (x >= b) return 0;
  return (b - x) / (b - a);
}

function alto(x, a, b) {
  if (x <= a) return 0;
  if (x >= b) return 1;
  return (x - a) / (b - a);
}

function triangular(x, a, b, c) {
  if (x <= a || x >= c) return 0;
  if (x === b) return 1;
  if (x < b) return (x - a) / (b - a);
  return (c - x) / (c - b);
}

// Variable 1: anticipación de la cita
// Poca anticipación aumenta riesgo.
// Mucha anticipación reduce riesgo.
const anticipacion_baja = bajo(anticipacion_horas, 6, 24);
const anticipacion_media = triangular(anticipacion_horas, 12, 48, 96);
const anticipacion_alta = alto(anticipacion_horas, 48, 120);

// Variable 2: historial del cliente
// Este historial viene de Google Sheets.
const historial_malo = bajo(historial_cliente, 0.3, 0.6);
const historial_regular = triangular(historial_cliente, 0.4, 0.6, 0.8);
const historial_bueno = alto(historial_cliente, 0.6, 0.9);

// Variable 3: confirmación del cliente
// Mide qué tan completa está la solicitud actual.
const confirmacion_baja = bajo(confirmacion_cliente, 0.3, 0.6);
const confirmacion_media = triangular(confirmacion_cliente, 0.4, 0.6, 0.8);
const confirmacion_alta = alto(confirmacion_cliente, 0.6, 0.9);

// Variable 4: hora de la cita
// Desde las 4 p.m. empieza a considerarse más demandada.
// Desde las 7 p.m. se considera totalmente alta demanda.
const hora_alta_demanda = alto(hora_cita, 16, 19);

// Variable 5: duración
// Una cita larga bloquea más tiempo, por eso puede aumentar el riesgo operativo.
const duracion_larga = alto(duracion, 45, 90);

// Reglas difusas

// Riesgo alto
const regla_riesgo_alto_1 = Math.min(anticipacion_baja, historial_malo);
const regla_riesgo_alto_2 = Math.min(confirmacion_baja, duracion_larga);
const regla_riesgo_alto_3 = Math.min(hora_alta_demanda, confirmacion_baja);
const regla_riesgo_alto_4 = Math.min(historial_malo, duracion_larga);

// Riesgo medio
const regla_riesgo_medio_1 = Math.min(anticipacion_media, historial_regular);
const regla_riesgo_medio_2 = Math.min(confirmacion_media, duracion_larga);
const regla_riesgo_medio_3 = Math.min(hora_alta_demanda, historial_regular);

// Riesgo bajo
const regla_riesgo_bajo_1 = Math.min(anticipacion_alta, historial_bueno);
const regla_riesgo_bajo_2 = Math.min(confirmacion_alta, historial_bueno);
const regla_riesgo_bajo_3 = Math.min(anticipacion_alta, confirmacion_alta);

// Agregación de reglas
const riesgo_bajo = Math.max(
  regla_riesgo_bajo_1,
  regla_riesgo_bajo_2,
  regla_riesgo_bajo_3
);

const riesgo_medio = Math.max(
  regla_riesgo_medio_1,
  regla_riesgo_medio_2,
  regla_riesgo_medio_3
);

const riesgo_alto = Math.max(
  regla_riesgo_alto_1,
  regla_riesgo_alto_2,
  regla_riesgo_alto_3,
  regla_riesgo_alto_4
);

// Defuzzificación simple por promedio ponderado
// Bajo = 0.2
// Medio = 0.5
// Alto = 0.85
const numerador =
  riesgo_bajo * 0.2 +
  riesgo_medio * 0.5 +
  riesgo_alto * 0.85;

const denominador =
  riesgo_bajo +
  riesgo_medio +
  riesgo_alto;

let riesgo_num = denominador === 0 ? 0.3 : numerador / denominador;
riesgo_num = Number(riesgo_num.toFixed(2));

// Acción racional según el riesgo
let riesgo_categoria;
let accion_racional;

if (riesgo_num < 0.35) {
  riesgo_categoria = 'bajo';
  accion_racional = 'crear cita normalmente';
} else if (riesgo_num < 0.65) {
  riesgo_categoria = 'medio';
  accion_racional = 'crear cita y enviar recordatorio';
} else {
  riesgo_categoria = 'alto';
  accion_racional = 'pedir doble confirmacion o alertar administrador';
}

return [
  {
    json: {
      ...item,

      anticipacion_horas,
      historial_cliente,
      historial_confianza,
      confirmacion_cliente,
      hora_cita,
      duracion,

      anticipacion_baja: Number(anticipacion_baja.toFixed(2)),
      anticipacion_media: Number(anticipacion_media.toFixed(2)),
      anticipacion_alta: Number(anticipacion_alta.toFixed(2)),

      historial_malo: Number(historial_malo.toFixed(2)),
      historial_regular: Number(historial_regular.toFixed(2)),
      historial_bueno: Number(historial_bueno.toFixed(2)),

      confirmacion_baja: Number(confirmacion_baja.toFixed(2)),
      confirmacion_media: Number(confirmacion_media.toFixed(2)),
      confirmacion_alta: Number(confirmacion_alta.toFixed(2)),

      hora_alta_demanda: Number(hora_alta_demanda.toFixed(2)),
      duracion_larga: Number(duracion_larga.toFixed(2)),

      riesgo_bajo: Number(riesgo_bajo.toFixed(2)),
      riesgo_medio: Number(riesgo_medio.toFixed(2)),
      riesgo_alto: Number(riesgo_alto.toFixed(2)),

      riesgo_num,
      riesgo_categoria,
      accion_racional
    }
  }
];
